package ru.kryuch.krtg.searcher.helper;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Component;import ru.kryuch.krtg.searcher.integration.TelegramPythonClient;import ru.kryuch.krtg.searcher.config.TelegramSettingsResolver;import ru.kryuch.krtg.searcher.dto.ChatInfo;import ru.kryuch.krtg.searcher.dto.MessagesHistory;import ru.kryuch.krtg.searcher.dto.SearchParams;import ru.kryuch.krtg.searcher.integration.dto.SendBulkMessageRequest;import ru.kryuch.krtg.searcher.mapper.ChatMapper;import ru.kryuch.krtg.searcher.util.PythonMessagesResponse;import ru.kryuch.krtg.searcher.util.SendResponse;import java.time.LocalDateTime;import java.time.format.DateTimeFormatter;import java.util.Arrays;import java.util.Collections;import java.util.List;import java.util.Objects;import java.util.Set;import java.util.stream.Collectors;@Slf4j@Component@RequiredArgsConstructorpublic class TelegramService {    private final TelegramPythonClient client;    private final TelegramSettingsResolver settings;    private final ChatMapper chatMapper;    public List<ChatInfo> getAll() {        ChatInfo[] response = client.findAllChats();        if (response == null) {            return Collections.emptyList();        }        return Arrays.asList(response);    }    public List<ChatInfo> search(SearchParams params) {        ChatInfo[] response = client.searchChats(params);        if (response == null) {            return Collections.emptyList();        }        return Arrays.asList(response);    }    public List<ChatInfo> sendMessage(String message,                                      Set<String> contacts,                                      boolean onlyNew) {        if (contacts == null || contacts.isEmpty()) {            return Collections.emptyList();        }        SendResponse response =                client.sendBulkMessages(                        SendBulkMessageRequest.builder()                                .chatIds(contacts.stream().map(item -> Long.parseLong(item)).collect(Collectors.toSet()))                                .messageText(message)                                .delaySeconds(settings.getSendDelay())                                .onlyNewChats(onlyNew)                                .build()                );        if (response == null || response.getResults() == null) {            return Collections.emptyList();        }        return response.getResults().stream()                .map(chatMapper::fromSendResult)                .filter(Objects::nonNull)                .toList();    }    public MessagesHistory getMessages(Long chatId, Integer limit) {        PythonMessagesResponse response =                client.getChatPreview(chatId, limit);        if (response == null || response.getMessages() == null) {            return new MessagesHistory();        }        MessagesHistory history = new MessagesHistory();        for (var msg : response.getMessages()) {            history.add(msg);        }        return history;    }    public List<ChatInfo> getChatsInfo(List<Long> chatIds) {        return client.findChatsByIds(chatIds);    }    private LocalDateTime parse(String date) {        return date == null                ? null                : LocalDateTime.parse(date,                DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));    }}